from urls import normalize_anthropic_base_url


def test_none_passthrough():
    assert normalize_anthropic_base_url(None) is None


def test_strip_trailing_v1():
    assert normalize_anthropic_base_url('https://api.example.com/v1') == 'https://api.example.com'


def test_keep_non_v1_path():
    assert normalize_anthropic_base_url('https://api.example.com/custom') == 'https://api.example.com/custom'

