import pytest

from parser import extract_choices


class Response:
    def __init__(self):
        self.choices = ['ok']


def test_valid_chat_response():
    assert extract_choices(Response()) == ['ok']


def test_string_payload_raises_clear_error():
    with pytest.raises(RuntimeError, match='non-OpenAI'):
        extract_choices('<html>gateway page</html>')
